#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long *a = (long long*)malloc(N * sizeof(long long));
        for(int i=0;i<N;i++) scanf("%lld", &a[i]);
        int idx; scanf("%d", &idx);
        if(idx==0) printf("NULL\n");
        else printf("%lld\n", a[idx-1]);
        free(a);
    }
    return 0;
}

